"use client";

import {
  MapPin,
  Star,
  Bed,
  WifiHigh,
  Mountains,
  SwimmingPool,
  Coffee,
  Heart,
  Sparkle,
  Sun,
} from "@phosphor-icons/react";
import type { Icon } from "@phosphor-icons/react";

interface FloatingPill {
  id: string;
  icon: Icon;
  label: string;
  x: string;
  y: string;
  rotation: number;
  driftClass: string;
}

const PILLS: FloatingPill[] = [
  { id: "p01", icon: MapPin,       label: "Lake Tahoe",    x: "3%",  y: "8%",  rotation: -3,  driftClass: "fp-drift-1" },
  { id: "p02", icon: Star,         label: "4.9 Rating",    x: "82%", y: "6%",  rotation: 4,   driftClass: "fp-drift-5" },
  { id: "p03", icon: Mountains,    label: "Mountain View", x: "88%", y: "22%", rotation: -2,  driftClass: "fp-drift-3" },
  { id: "p04", icon: Bed,          label: "3 Bedrooms",    x: "5%",  y: "28%", rotation: 5,   driftClass: "fp-drift-2" },
  { id: "p05", icon: WifiHigh,     label: "Fast WiFi",     x: "90%", y: "40%", rotation: -4,  driftClass: "fp-drift-6" },
  { id: "p06", icon: SwimmingPool, label: "Heated Pool",   x: "2%",  y: "48%", rotation: 3,   driftClass: "fp-drift-4" },
  { id: "p07", icon: Coffee,       label: "Coffee Bar",    x: "85%", y: "56%", rotation: 2,   driftClass: "fp-drift-1" },
  { id: "p08", icon: Sun,          label: "Sunny Patio",   x: "6%",  y: "66%", rotation: -5,  driftClass: "fp-drift-3" },
  { id: "p09", icon: Heart,        label: "Guest Fave",    x: "88%", y: "72%", rotation: 3,   driftClass: "fp-drift-2" },
  { id: "p10", icon: Sparkle,      label: "Superhost",     x: "4%",  y: "12%", rotation: -2,  driftClass: "fp-drift-5" },
];

export default function FloatingPills() {
  return (
    <div aria-hidden="true" className="absolute inset-0 overflow-hidden pointer-events-none z-[1] hidden md:block">
      {PILLS.map((pill) => {
        const IconComp = pill.icon;
        return (
          <div
            key={pill.id}
            className={`fp-pill ${pill.driftClass}`}
            style={{ position: "absolute", left: pill.x, top: pill.y, transform: `rotate(${pill.rotation}deg)` }}
          >
            <IconComp size={16} weight="bold" />
            <span>{pill.label}</span>
          </div>
        );
      })}
      <style>{`
        .fp-pill {
          display: flex; align-items: center; gap: 6px;
          padding: 8px 14px; border-radius: 100px;
          background: rgba(255,255,255,0.15);
          backdrop-filter: blur(16px) saturate(160%);
          -webkit-backdrop-filter: blur(16px) saturate(160%);
          border: 1px solid rgba(255,255,255,0.2);
          color: rgba(255,255,255,0.75);
          font-size: 13px; font-weight: 500; white-space: nowrap;
          opacity: 0.6; box-shadow: 0 4px 16px rgba(0,0,0,0.12);
        }
        @keyframes fp-drift-1 { 0%{transform:translate(0,0) rotate(0deg)} 33%{transform:translate(18px,10px) rotate(1.5deg)} 66%{transform:translate(-10px,18px) rotate(-1deg)} 100%{transform:translate(0,0) rotate(0deg)} }
        @keyframes fp-drift-2 { 0%{transform:translate(0,0) rotate(0deg)} 33%{transform:translate(-14px,-12px) rotate(-2deg)} 66%{transform:translate(12px,-6px) rotate(1deg)} 100%{transform:translate(0,0) rotate(0deg)} }
        @keyframes fp-drift-3 { 0%{transform:translate(0,0)} 50%{transform:translate(14px,-10px)} 100%{transform:translate(0,0)} }
        @keyframes fp-drift-4 { 0%{transform:translate(0,0) rotate(0deg)} 40%{transform:translate(-8px,14px) rotate(1deg)} 80%{transform:translate(10px,6px) rotate(-0.5deg)} 100%{transform:translate(0,0) rotate(0deg)} }
        @keyframes fp-drift-5 { 0%{transform:translate(0,0)} 35%{transform:translate(12px,-8px)} 70%{transform:translate(-6px,-14px)} 100%{transform:translate(0,0)} }
        @keyframes fp-drift-6 { 0%{transform:translate(0,0) rotate(0deg)} 50%{transform:translate(-16px,8px) rotate(2deg)} 100%{transform:translate(0,0) rotate(0deg)} }
        .fp-drift-1{animation:fp-drift-1 22s ease-in-out infinite}
        .fp-drift-2{animation:fp-drift-2 18s ease-in-out infinite}
        .fp-drift-3{animation:fp-drift-3 25s ease-in-out infinite}
        .fp-drift-4{animation:fp-drift-4 20s ease-in-out infinite}
        .fp-drift-5{animation:fp-drift-5 16s ease-in-out infinite}
        .fp-drift-6{animation:fp-drift-6 24s ease-in-out infinite}
        @media(prefers-reduced-motion:reduce){.fp-drift-1,.fp-drift-2,.fp-drift-3,.fp-drift-4,.fp-drift-5,.fp-drift-6{animation:none}}
      `}</style>
    </div>
  );
}
